p.place_id LIKE '%' || #{intKeyword} || '%'
ORDER BY p.updated_at DESC ) A WHERE ROWNUM <= #{end} ) WHERE rn >= #{start}

SELECT * FROM ( SELECT A.*, ROWNUM AS rn FROM ( SELECT p.place_id AS "place_id", p.place_type AS "place_type", p.name AS "name", p.address AS "address", p.view_count AS "view_count", p.image_url AS "image_url", p.updated_at AS "placeUpdateDate", a.category AS "category" FROM PLACE p JOIN ACCOMMODATION a ON p.place_id = a.accommodation_id
p.name LIKE '%' || #{strKeyword} || '%'
